module.exports = {
  ci: {
    collect: {
      startServerCommand: 'npm run preview',
      startServerReadyPattern: 'Local',
      url: [
        'http://localhost:4321/',
        'http://localhost:4321/styleguide/',
        'http://localhost:4321/404.html',
      ],
      numberOfRuns: 3,
    },
    assert: {
