interface Props {
  title: string;
  subtitle?: string;
  ctaText?: string;
  ctaHref?: string;
  backgroundImage: string;
}

const { title, subtitle, ctaText, ctaHref, backgroundImage } = Astro.props;
---

<section
  class="hero"
  style={`background-image: url('${backgroundImage}');`}
>
  <div class="hero__overlay">
    <div class="hero__content">
      <h1 class="hero__title">{title}</h1>
      {subtitle && <p class="hero__subtitle">{subtitle}</p>}
      {ctaText && ctaHref && (
        <a class="hero__cta" href={ctaHref}>{ctaText}</a>
      )}
    </div>
  </div>
</section>

<style>
  .hero {
    width: 100%;
    min-height: 28rem;
    background-size: cover;
    background-position: center;
    background-repeat: no-repeat;
    position: relative;
    display: flex;
    align-items: center;
    justify-content: center;
  }

  .hero__overlay {
    position: absolute;
    inset: 0;
    background: linear-gradient(
      to bottom,
      rgba(26, 26, 46, 0.55) 0%,
      rgba(26, 26, 46, 0.72) 100%
    );
    display: flex;
    align-items: center;
    justify-content: center;
  }

  .hero__content {
    position: relative;
    text-align: center;
    max-width: var(--max-width);
    padding: var(--space-12) var(--space-6);
    color: var(--color-bg);
  }

  .hero__title {
    font-family: var(--font-heading);
    font-size: var(--text-4xl);
    line-height: var(--leading-tight);
    color: var(--color-bg);
    margin-block-end: var(--space-4);
  }

  .hero__subtitle {
    font-family: var(--font-body);
    font-size: var(--text-lg);
    line-height: var(--leading-relaxed);
    color: var(--color-stone);
    max-width: 36rem;
    margin-inline: auto;
    margin-block-end: var(--space-8);
  }

  .hero__cta {
    display: inline-block;
    font-family: var(--font-body);
    font-size: var(--text-base);
    font-weight: 600;
    color: var(--color-bg);
    background-color: var(--color-terracotta);
    padding: var(--space-3) var(--space-8);
    border-radius: var(--radius-md);
    text-decoration: none;
    transition: background-color var(--transition), transform var(--transition);
  }

  .hero__cta:hover {
    background-color: #b3654b;
    transform: translateY(-1px);
  }

  .hero__cta:focus-visible {
    outline: 2px solid var(--color-focus);
    outline-offset: 2px;
  }

  @media (max-width: 768px) {
    .hero {
      min-height: 22rem;
    }

    .hero__title {
      font-size: var(--text-2xl);
    }

    .hero__subtitle {
      font-size: var(--text-base);
    }

    .hero__content {
      padding: var(--space-8) var(--space-4);
    }
  }
</style>

